import{_ as t,c as s,o as l,a5 as r,j as a}from"./chunks/framework.Dtwt352Q.js";const k=JSON.parse('{"title":"v1.1.56：Task 渲染修复、Windows 打开应用更顺手","description":"","frontmatter":{},"headers":[],"relativePath":"changelog/v1.1.56.md","filePath":"changelog/v1.1.56.md","lastUpdated":1772014034000}'),i={name:"changelog/v1.1.56.md"};function n(o,e,d,h,c,p){return l(),s("div",null,[...e[0]||(e[0]=[r('<h1 id="v1-1-56-task-渲染修复、windows-打开应用更顺手" tabindex="-1">v1.1.56：Task 渲染修复、Windows 打开应用更顺手 <a class="header-anchor" href="#v1-1-56-task-渲染修复、windows-打开应用更顺手" aria-label="Permalink to “v1.1.56：Task 渲染修复、Windows 打开应用更顺手”">​</a></h1><p><strong>发布日期</strong>：2026年02月11日</p><hr><h2 id="一句话总结" tabindex="-1">一句话总结 <a class="header-anchor" href="#一句话总结" aria-label="Permalink to “一句话总结”">​</a></h2><p>这是一个桌面端体验修复版本：Task 工具渲染问题修复、Windows 现在支持用可执行程序打开应用、切换会话时侧边栏不再自动收起。</p><hr><h2 id="问题修复-task-工具在桌面端渲染异常" tabindex="-1">问题修复：Task 工具在桌面端渲染异常 <a class="header-anchor" href="#问题修复-task-工具在桌面端渲染异常" aria-label="Permalink to “问题修复：Task 工具在桌面端渲染异常”">​</a></h2><h3 id="之前的问题" tabindex="-1">之前的问题 <a class="header-anchor" href="#之前的问题" aria-label="Permalink to “之前的问题”">​</a></h3><p>在桌面应用里，Task 工具相关内容存在渲染异常，影响阅读和操作。</p><h3 id="现在的情况" tabindex="-1">现在的情况 <a class="header-anchor" href="#现在的情况" aria-label="Permalink to “现在的情况”">​</a></h3><p>v1.1.56 已修复渲染问题，Task 执行过程显示更稳定。</p><h3 id="如何使用" tabindex="-1">如何使用？ <a class="header-anchor" href="#如何使用" aria-label="Permalink to “如何使用？”">​</a></h3><p>👉 <strong>完整教程</strong>：<a href="/5-advanced/02c-agent-permissions.html">Agent 权限与安全</a></p><p>👉 <strong>官方文档</strong>：<a href="https://opencode.ai/docs/commands#subtask" target="_blank" rel="noreferrer">Commands / Subtask</a></p><p><strong>快速体验</strong>：</p><ol><li>在桌面端发起需要子任务的请求。</li><li>观察 Task 输出和步骤渲染是否正常。</li><li>在同一会话中重复触发，确认显示稳定。</li></ol><hr><h2 id="新功能-windows-支持通过可执行程序打开应用" tabindex="-1">新功能：Windows 支持通过可执行程序打开应用 <a class="header-anchor" href="#新功能-windows-支持通过可执行程序打开应用" aria-label="Permalink to “新功能：Windows 支持通过可执行程序打开应用”">​</a></h2><h3 id="这次更新了什么" tabindex="-1">这次更新了什么？ <a class="header-anchor" href="#这次更新了什么" aria-label="Permalink to “这次更新了什么？”">​</a></h3><p>桌面端新增了在 Windows 中通过可执行程序打开应用的能力。</p><h3 id="这对你有什么用" tabindex="-1">这对你有什么用？ <a class="header-anchor" href="#这对你有什么用" aria-label="Permalink to “这对你有什么用？”">​</a></h3><p>本地工具联动更直接，不需要绕很多手动步骤，尤其在企业环境里更实用。</p><h3 id="如何使用-1" tabindex="-1">如何使用？ <a class="header-anchor" href="#如何使用-1" aria-label="Permalink to “如何使用？”">​</a></h3><p>👉 <strong>完整教程</strong>：<a href="/2-daily/01-interface.html">2.1 界面与操作</a></p><p><strong>快速体验</strong>：</p><ol><li>在 Windows 桌面端打开相关入口。</li><li>选择目标应用或文件并触发打开。</li><li>确认系统使用预期可执行程序启动。</li></ol><hr><h2 id="改进-切换会话不再自动收起侧边栏" tabindex="-1">改进：切换会话不再自动收起侧边栏 <a class="header-anchor" href="#改进-切换会话不再自动收起侧边栏" aria-label="Permalink to “改进：切换会话不再自动收起侧边栏”">​</a></h2><h3 id="这次更新了什么-1" tabindex="-1">这次更新了什么？ <a class="header-anchor" href="#这次更新了什么-1" aria-label="Permalink to “这次更新了什么？”">​</a></h3><p>切换会话时，侧边栏状态会保留，不会被自动关闭。</p><h3 id="这对你有什么用-1" tabindex="-1">这对你有什么用？ <a class="header-anchor" href="#这对你有什么用-1" aria-label="Permalink to “这对你有什么用？”">​</a></h3><p>多会话来回切换时操作更连贯，尤其适合需要频繁对比上下文的工作流。</p><hr><h2 id="要不要升级" tabindex="-1">要不要升级？ <a class="header-anchor" href="#要不要升级" aria-label="Permalink to “要不要升级？”">​</a></h2><table tabindex="0"><thead><tr><th>情况</th><th>建议</th></tr></thead><tbody><tr><td>你主要用桌面端</td><td>✅ 建议升级</td></tr><tr><td>你在 Windows 上工作</td><td>✅ 建议升级</td></tr><tr><td>你经常用 Task/子任务</td><td>✅ 建议升级</td></tr><tr><td>用得好好的</td><td>可以等下次</td></tr></tbody></table><p><strong>升级命令</strong>：</p>',36),a("div",{class:"language-bash"},[a("button",{title:"Copy Code",class:"copy"}),a("span",{class:"lang"},"bash"),a("pre",null,[a("code",{"v-pre":""},"opencode upgrade")])],-1),r('<hr><h2 id="技术细节-可跳过" tabindex="-1">技术细节（可跳过） <a class="header-anchor" href="#技术细节-可跳过" aria-label="Permalink to “技术细节（可跳过）”">​</a></h2><details><summary>点击展开完整更新列表</summary><h3 id="desktop" tabindex="-1">Desktop <a class="header-anchor" href="#desktop" aria-label="Permalink to “Desktop”">​</a></h3><ul><li>Task tool rendering fixed in app</li><li>Open apps with executables on Windows</li><li>Don&#39;t close sidebar on session change</li></ul><p>官方 Release Notes：</p><ul><li><a href="https://github.com/anomalyco/opencode/releases/tag/v1.1.56" target="_blank" rel="noreferrer">https://github.com/anomalyco/opencode/releases/tag/v1.1.56</a></li></ul></details><hr><p><a href="./">← 返回更新日志</a></p>',5)])])}const m=t(i,[["render",n]]);export{k as __pageData,m as default};
